INSERT INTO doi_invoice_resc (
YYYYMM,SEL_CODE,SITE,선택,출고처리,사업단위,Invoice_No,Invoice관리번호,Invoice_Date,수출구분,	
출고구분,가격조건,부서,담당자,Buyer,Agent,통화,환율,품명,품번,규격,단위,판매기준가,판매단가,수량,
판매금액,원화판매금액,창고,납기일,기타출고구분,진행상태,매출진행상태,매출대상,매출금액계,미매출금액,
Remarks,특이사항
)
SELECT
YYYYMM,SEL_CODE,SITE,선택,출고처리,사업단위,Invoice_No,Invoice관리번호,Invoice_Date,수출구분,	
출고구분,가격조건,부서,담당자,Buyer,Agent,통화,환율,품명,품번,규격,단위,판매기준가,판매단가,수량,
판매금액,원화판매금액,창고,납기일,기타출고구분,진행상태,매출진행상태,매출대상,매출금액계,미매출금액,
Remarks,특이사항
FROM #TempTable a
WHERE 1=1
AND NOT EXISTS (
	SELECT 1
	FROM doi_invoice_resc b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.Invoice관리번호 = a.Invoice관리번호
);

